class Solution: def solve(self, A: list[int]) -> bool: bitmask = 0; for x in A: bitmask ^= x; return bitmask == 0;
def readArray():
    A = [int(x) for x in input().split()]; return A;
A = readArray(); s = Solution(); print(s.solve(A));

solutions.javascript:
function solve(A) { let bitmask = 0; for (let x of A) bitmask ^= x; return bitmask == 0; }
function readArray(readline) { return readline().split(' ').map(Number); }
var readline = require('readline');
var rl = readline.createInterface({ input: process.stdin, output: process.stdout });
rl.on('line', (input) => { var A = readArray(rl.readLine); var s = solve(A); console.log(s ? 'T' : 'F'); rl.close(); });
